def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 4, -1):
                for b in range(2, a + 4):
                    base = (ratio - a) ** 6 / (a * b * 1.1 + 0.9)
                    trig = np.cos(ratio * b / (a + 2)) + np.sin(ratio * a / (b + 1))
                    priority += base * trig * np.exp(-0.1 * (a + b + i))
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 1.75
            priority -= np.log(ratio) * 2
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    term1 = ((ratio - p) ** 4) * np.sin(ratio * p / (q + 0.3))
                    term2 = np.tanh(term1) * 1.5
                    priority += term2 - np.cos(ratio * q) * 0.7
            priority += np.log(ratio) * 8 - np.tanh(ratio - 5) * 3
            for k in range(1, 5):
                priority += np.sin(ratio * k * i / 2) * np.exp(-0.05 * k)
        elif 2 < ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.1) * np.cos(r * ratio * 1.1) * np.tanh(r / (ratio + 0.1))
            priority = (s * np.cos(6.5 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (5 - ratio)) * 2
            for m in range(1, 6):
                priority += np.sin(m * ratio * i / 1.3) * ((ratio - 1.9) ** m) / m
        elif 1 <= ratio <= 2:
            s = 0
            for n in range(1, 12):
                power = ((2 - ratio) ** n) / (n ** 2 + 1.2)
                trig = np.exp(-0.1 * n) * np.cos(n * ratio * 2.2)
                s += power * trig
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.1))
            for t in range(1, 7):
                priority += np.sin(t * ratio * i * 0.9) * ((ratio - 1) ** t) / t
        elif 0.5 <= ratio < 1:
            s = 0
            for u in range(1, 18):
                s += ((1 - ratio) ** u) / (u * 3.5) * np.sin(u * ratio * 1.8)
            priority = s * np.log1p(bin_cap + 2) - np.tanh(5 * (1 - ratio)) * 2
            if (i + int(item * 2)) % 5 == 1:
                priority *= np.sqrt(bin_cap + 2) * 1.8
            else:
                priority /= (np.sqrt(bin_cap + 1.2) + 3)
            for v in range(1, 8):
                priority += ((1 - ratio) ** v) * np.cos(v * item * 1.5) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for w in range(1, 20):
                val = ((0.5 - ratio) ** w) / (w * 2.5)
                s += val * np.cos(w * ratio * 2.5) * np.sin(w * item * 1.3)
            priority = s + 1 / (bin_cap + 4) - np.exp(-ratio * 1.5) * 2
            if int(item * 1.7) % 6 == 2:
                priority *= 2.8
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            for x in range(1, 9):
                priority += ((0.5 - ratio) ** x) / (x * 7) * np.cos(item * x * 1.0)
        else:
            s = 0
            for y in range(1, 14):
                s += ((0.2 - ratio) ** y) / (y * 6) * np.sin(y * item * 1.0) * np.tanh(y / (ratio + 0.2))
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 3:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.2) * 5
            for z in range(1, 10):
                priority += ((0.2 - ratio) ** z) / (z * 8) * np.cos(item * z * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5
            for alpha in range(1, 5):
                priority += np.sin(alpha * ratio * i) * ((ratio - 0.7) ** alpha) * 0.4
        elif bin_cap > item * 3:
            priority -= np.exp(-3.5 * ratio) * 5
            for beta in range(2, 6):
                priority -= np.cos(beta * ratio * (i + 1)) * 0.35
        for idx in range(1, 5):
            if (i + idx * 2) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 1:
            priority += np.sin(ratio * i * 1.2) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.2) * 0.7
        if (i * item) % 3 == 0:
            priority += np.tanh(ratio * i) * 1.1
        else:
            priority -= np.tanh(ratio / (i + 1)) * 1.1
        priorities[i] = priority
    return priorities
